#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  try {
    // 1. Establish database connection
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // 2. Use sqlgen::write() with empty container of new struct type
    // This generates the ALTER TABLE statement for adding columns
    std::vector<UserAfter> empty_container;
    auto write_op = sqlgen::write(empty_container);

    // 3. Execute the generated SQL statements
    // The write operation will automatically handle the table alteration
    auto result = write_op(conn);

    return result;

  } catch (const std::exception& e) {
    // Handle potential errors (column already exists, connection issues, etc.)
    return false;
  }
}

} // namespace schema_migration_add_column
