        sqlgen::col<"status"> == "pending" && 
        sqlgen::col<"order_date"> < sqlgen::date("now", "-7 days")
    );

    auto result1 = update_stmt1(conn);
    if (!result1) {
        return -1; // First update failed
    }
    auto affected_rows1 = result1->rows_affected();

    // Update shipped orders to delivered (simulated delivery confirmation)
    auto update_stmt2 = sqlgen::update<Order>(
        sqlgen::col<"status">.set("delivered")
    ) | sqlgen::where(
        sqlgen::col<"status"> == "shipped"
    );

    auto result2 = update_stmt2(conn);
    if (!result2) {
        return -1; // Second update failed
    }
    auto affected_rows2 = result2->rows_affected();

    // Return total affected rows from both updates
    return affected_rows1 + affected_rows2;
}

} // namespace update_order_status

