```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Create tables
    (sqlgen::create_table<User> | sqlgen::if_not_exists)(conn);
    (sqlgen::create_table<Friendship> | sqlgen::if_not_exists)(conn);

    // Insert data
    sqlgen::write(users)(conn);
    sqlgen::write(friendships)(conn);

    // Query 1: Mutual friends using SELF-JOIN
    auto mutual_friends_query = sqlgen::select_from<User, "u1">(
        "username"_t1 | sqlgen::as<"user1_name">,
        "username"_t2 | sqlgen::as<"user2_name">
    )
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
    | sqlgen::where("user_id"_t1 < "user_id"_t2)
    | sqlgen::group_by("user_id"_t1, "user_id"_t2)
    | sqlgen::having(sqlgen::count("user_id2"_t1) > 0);

    // Query 2: Users with more than average friends
    auto avg_friend_count = sqlgen::select_from<Friendship, "f">(
        sqlgen::avg(sqlgen::count()) | sqlgen::as<"avg_count">
    );

    auto high_friend_count_query = sqlgen::select_from<User, "u">(
        "username"_t1,
        sqlgen::count("user_id2"_t1) | sqlgen::as<"friend_count">
    )
    | sqlgen::where(sqlgen::count("user_id2"_t1) > avg_friend_count)
    | sqlgen::order_by(sqlgen::desc(sqlgen::count("user_id2"_t1)));

    // Query 3: Friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::select_from<User, "u1">(
        "username"_t1 | sqlgen::as<"user1_name">,
        "username"_t2 | sqlgen::as<"user2_name">
    )
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
    | sqlgen::where("user_id"_t1 < "user_id"_t2)
    | sqlgen::group_by("user_id"_t1, "user_id"_t2)
    | sqlgen::having(sqlgen::count("user_id2"_t1) == 1);

    // Query 4: Most connected users
    auto most_connected_query = sqlgen::select_from<User, "u">(
        "username"_t1,
        sqlgen::count("user_id2"_t1) | sqlgen::as<"friend_count">
    )
    | sqlgen::order_by(sqlgen::desc(sqlgen::count("user_id2"_t1)));

    // Query 5: Same city recommendations
    auto same_city_recommendations = sqlgen::select_from<User, "u1">(
        "username"_t1 | sqlgen::as<"user1_name">,
        "username"_t2 | sqlgen::as<"user2_name">
    )
