bool update_set_operations() {
  using namespace sqlgen::literals;

  try {
    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = conn_result.value();

    // 2. Create the Account table
    auto create_result = (sqlgen::create_table<Account> | sqlgen::if_not_exists)(conn);
    if (!create_result) {
      return false;
    }

    // 3. Insert initial data
    std::vector<Account> initial_data = {
        Account{1, 100.0, "active"},
        Account{2, 200.0, "inactive"}
    };

    auto write_result = sqlgen::write(conn, initial_data);
    if (!write_result) {
      return false;
    }

    // 4. Update balance and status using set()
    auto update_result = (sqlgen::update<Account>(
        "balance"_c.set(300.0),
        "status"_c.set("updated")
    ) | sqlgen::where("account_id"_c == 1))(conn);

