 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Create SQLite connection
  auto conn = sqlgen::sqlite::connect(":memory:").value();

  // 2. Create tables with if_not_exists
  (sqlgen::create_table<Department> | sqlgen::if_not_exists)(conn).value();
  (sqlgen::create_table<Employee> | sqlgen::if_not_exists)(conn).value();

  // 3. Insert data
  sqlgen::write(conn, depts)(conn).value();
  sqlgen::write(conn, emps)(conn).value();

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
    | sqlgen::to<std::vector<JoinResult>>;

  auto inner_results = inner_query(conn).value();

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2,
      "department_name"_t1
  ) | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
    | sqlgen::to<std::vector<JoinResult>>;

  auto left_results = left_query(conn).value();

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
    | sqlgen::to<std::vector<JoinResult>>;

  auto right_results = right_query(conn).value();

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1,
      "first_name"_t2,
      "last_name"_t2,
      "salary"_t2
  ) | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
    | sqlgen::to<std::vector<JoinResult>>;

  auto full_results = full_query(conn).value();

  // 8. Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = std::move(inner_results),
      .left_join_results = std::move(left_results),
      .right_join_results = std::move(right_results),
      .full_join_results = std::move(full_results)
  };
}

}  // namespace analyze_department_employees
